const cache = new Map();
let fetchCount = 0;

async function expensiveFetch(key) {
  fetchCount++;
  await new Promise(r => setTimeout(r, 50));
  return { key, value: `data-for-${key}`, fetchedAt: Date.now() };
}

export async function getCached(key) {
  if (cache.has(key)) {
    return cache.get(key);
  }
  const result = await expensiveFetch(key);
  cache.set(key, result);
  return result;
}

export function getFetchCount() {
  return fetchCount;
}

export function clearCache() {
  cache.clear();
  fetchCount = 0;
}

