import { getCached, getFetchCount, clearCache } from './src/cache.js';
import assert from 'node:assert/strict';

// Test 1: Basic caching works
clearCache();
const r1 = await getCached('a');
const r2 = await getCached('a');
assert.equal(r1.value, 'data-for-a');
assert.equal(r1, r2, 'Second call should return cached result');
assert.equal(getFetchCount(), 1, 'Should only fetch once for cached key');

// Test 2: Different keys fetch separately
clearCache();
await getCached('x');
await getCached('y');
assert.equal(getFetchCount(), 2);

// Test 3: THE HARD PART — concurrent calls to the same key
// should only trigger ONE fetch, not multiple
clearCache();
const concurrent = await Promise.all([
  getCached('same'),
  getCached('same'),
  getCached('same'),
  getCached('same'),
  getCached('same'),
]);

assert.equal(getFetchCount(), 1, `Concurrent calls should deduplicate fetches. Got ${getFetchCount()} fetches instead of 1`);
assert.ok(concurrent.every(r => r.value === 'data-for-same'), 'All should return same result');
assert.ok(concurrent.every(r => r === concurrent[0]), 'All should be the exact same object reference');

// Test 4: After resolution, subsequent calls still use cache
const afterConcurrent = await getCached('same');
assert.equal(getFetchCount(), 1, 'Should still be 1 fetch after concurrent resolution');
assert.equal(afterConcurrent, concurrent[0]);

console.log('All tests passed');
